                fieldLabel: gr.assigned_to_individual.getLabel(),
                type: 'reference',
                hasValue: true,
                keyUsesDisplayOnly: false,
                hasDiplayValue: true,
                maxChars: 0
            },
            'calchaschildren': {
                fieldName: 'calchaschildren',
                fieldLabel: gr.calchaschildren.getLabel(),
                type: 'number',
                hasValue: true,
                keyUsesDisplayOnly: false,
                hasDiplayValue: false,
                maxChars: 0
            },
            'classification': {
                fieldName: 'classification',
                fieldLabel: gr.classification.getLabel(),
                type: 'choice',
                hasValue: true,
                keyUsesDisplayOnly: false,
                hasDiplayValue: true,
                maxChars: 0
            },
            'duration': {
                fieldName: 'duration',
                fieldLabel: gr.duration.getLabel(),
                type: 'date',
                hasValue: true,
                keyUsesDisplayOnly: false,
                hasDiplayValue: true,
                maxChars: 0
            },
            'instructions': {
                fieldName: 'instructions',
                fieldLabel: gr.instructions.getLabel(),
                type: 'string',
                hasValue: false,
                keyUsesDisplayOnly: true,
                hasDiplayValue: false,
                maxChars: 300
            },
            'number': {
                fieldName: 'number',
                fieldLabel: gr.number.getLabel(),
                type: 'number',
                hasValue: true,
                keyUsesDisplayOnly: true,
                hasDiplayValue: false,
                maxChars: 0
            },
            'parent': {
                fieldName: 'parent',
                fieldLabel: gr.parent.getLabel(),
                type: 'reference',
                hasValue: true,
                keyUsesDisplayOnly: false,
                hasDiplayValue: false,
                maxChars: 0
            },
            'primary_assignee': {
                fieldName: 'primary_assignee',
                fieldLabel: gr.primary_assignee.getLabel(),
                type: 'reference',
                hasValue: true,
                keyUsesDisplayOnly: false,
                hasDiplayValue: true,
                maxChars: 0
            },
            'primary_office': {
                fieldName: 'primary_office',
                fieldLabel: gr.primary_office.getLabel(),
                type: 'reference',
                hasValue: true,
                keyUsesDisplayOnly: false,
                hasDiplayValue: true,
                maxChars: 0
            },
            'route_order': {
                fieldName: 'route_order',
                fieldLabel: gr.route_order.getLabel(),
                type: 'string',
                hasValue: false,
                keyUsesDisplayOnly: true,
                hasDiplayValue: false,
                maxChars: 0
            },
            'short_description': {
                fieldName: 'short_description',
                fieldLabel: gr.short_description.getLabel(),
                type: 'string',
                hasValue: false,
                keyUsesDisplayOnly: true,
                hasDiplayValue: false,
                maxChars: 0
            },
            'tasker_type': {
                fieldName: 'tasker_type',
                fieldLabel: gr.tasker_type.getLabel(),
                type: 'reference',
