	buildTemplateMap: function(widgetId, map, gr, fields){
		var topTempTaskO = this.getTemplateTreeLevelO(gr, fields, 1, widgetId);
        // the top node of the tree cannot have a parent
        delete topTempTaskO.parent;

		// STRY0097904
		topTempTaskO.process_level_map = gr.tasker_process_definition.process_level.getDisplayValue();
		topTempTaskO.process_name_map = gr.number.toString() + ' - ' + gr.short_description.toString();
		map.push(topTempTaskO);
		//this.getTemplateTreeLeveln(widgetId,fields, map, topTempTaskO.level, topTempTaskO, topTempTaskO.sys_id);
		this.getTemplateTasks(widgetId,fields, map, topTempTaskO.level, topTempTaskO, topTempTaskO.sys_id);
	},

    getTemplateTreeLevelO: function(record, fields, level, widgetId) {
        var displayValue = '';
        var newNodeData = {};
        var sys_id = record.getUniqueValue();
        newNodeData.key = sys_id;
        newNodeData.sys_id = sys_id;
        newNodeData.level = level;
        for (var key in fields) {
            var field = fields[key];
            displayValue = record.getDisplayValue(key) + '';

            if (field.maxChars > 0)
                displayValue = displayValue.toString().length > field.maxChars ? displayValue.substring(0, field.maxChars - 1) : displayValue.toString();
            var fieldLabel = '';
            fieldLabel = field.fieldLabel;
            if (field.keyUsesDisplayOnly) {
                newNodeData[key] = displayValue;
            }
            if (field.hasValue) {
                newNodeData[key] = record.getValue(key);
            }
            if (field.hasDiplayValue) {
                newNodeData[key + '_DisplayValue'] = displayValue;
            }
            if (field.type == 'date') {
				// STRY0091251
				// var dateValue = new GlideDateTime();
				// dateValue.setDisplayValueInternal(record.getValue(key));
                // newNodeData[key] = dateValue.getNumericValue();
                newNodeData[key] = record[key].dateNumericValue();
//gs.info(('RJ - testing - newNodeData[key]: ' + newNodeData[key]));
            }
            if (field.type == 'boolean') {
                var boolean_value = record[key] == 1;
                newNodeData[key] = boolean_value;
            }
        }

        // These are the custom fields in this data set, compare with other data sets and determine best way to bring together.
        if (widgetId == 'discovertasker-recursivetasktreelist') {
            newNodeData.text = this.getTaskTreeListTitleNode(newNodeData, newNodeData.parent, newNodeData.task_name, newNodeData.primary_assignee, newNodeData.assigned_to, newNodeData.state, newNodeData.order);
            // we will expand all on initial page load
            newNodeData.expanded = true;
            // NOTE you are here, there is an issue with leaf nodes having the down chevron when they should not	
            // this should be removed
            newNodeData.href = '/discovertaskerportal?id=discovertasker_taskdetails&sys_id=' + newNodeData.sys_id + '&table=x_153465_discovert_route_task_instance&view=sp' + '&state=' + newNodeData['state'] + '&order=' + newNodeData['order'];
        }
        // Load the name value for the Task Tree Graph
        if (widgetId == 'discovertasker-recursivetasktreegraph') {
            newNodeData.name = this.getTaskTitleNode(record);
			newNodeData.warning = {};
        }
        // Load the name value for the Task Tree Graph
        if (widgetId == 'discovertasker-processtemplatetreegraph') {
            newNodeData.name = this.getTemplateTitleNode(record);
			newNodeData.warning = {};
        }
        return newNodeData;
    },
    //------------------------------------------------------------------------------------------------------------------------
    // Template has to set the name a little differntly than task
    //------------------------------------------------------------------------------------------------------------------------
    getTemplateTitleNode: function(grTemplateTask) {
		var nodeTitle = grTemplateTask.number.toString() + ' - ' + grTemplateTask.short_description.toString() + ' (' + grTemplateTask.primary_assignee.getDisplayValue().toString() + ')';
		if ((grTemplateTask.parent != '') && (parseInt(grTemplateTask.route_order.getDisplayValue().toString()) > 0))	
			nodeTitle = grTemplateTask.route_order.getDisplayValue().toString() + ". " + nodeTitle;
		return nodeTitle;
        //------------------------------------------------------------------------------------------------------------------------
    },

	//Get Template Tasks Level 1++
	getTemplateTasks: function(widgetId, fields, map, level, TemplateTaskO, sys_id) {
		var grTempTask = new GlideRecordSecure('x_153465_discovert_route_tasks');
		grTempTask.addQuery('parent', sys_id);
		grTempTask.orderBy('route_order');
		grTempTask.orderBy('number');
		grTempTask.query();

		// these the variables are used to build the duration total at each level
		var sumSubTaskTemplateDuration = 0;
		var currentOrder = 0;
		var orderMax = 0;
		var singleSubtaskLongerThanParent = false;
		while (grTempTask.next()) {
			var taskLevelO = this.getTemplateTreeLevelO(grTempTask, fields, level, widgetId);
			// order changed, reset orderMax
			if (currentOrder != parseInt(grTempTask.route_order)){
				sumSubTaskTemplateDuration += orderMax;
				orderMax = 0;
				currentOrder = parseInt(grTempTask.route_order);
			}
			// STRY0091251
			taskLevelO.warning.isParentShorterThanThisTask = (taskLevelO.duration > TemplateTaskO.duration);
			map.push(taskLevelO);
			this.getTemplateTasks(widgetId, fields, map, level + 1, taskLevelO, grTempTask.getUniqueValue());
			// check duration ageainst current max for the order
			if (taskLevelO.duration > orderMax){
				orderMax = parseInt(taskLevelO.duration);
			}
			// STRY0091251
			if(taskLevelO.duration > TemplateTaskO.duration){
				singleSubtaskLongerThanParent = true;
			}
		}
		if (widgetId == 'discovertasker-processtemplatetreegraph') {
			// the last task template order will not increase the order number.  So, add the last orderMax to the sum total of the children.
			TemplateTaskO.totalChildDuration = sumSubTaskTemplateDuration + orderMax;
			// STRY0091251
			TemplateTaskO.warning.isSubTaskLongerThanParent = (singleSubtaskLongerThanParent);
			TemplateTaskO.warning.waitStatewithNoSubtasks = (TemplateTaskO.u_wait_for_subtasks_to_finish && (TemplateTaskO.calchaschildren==0));
			// STRY0091251 - if a single child is longer than the parent, only show that message, and don't show the some of children message
			if(parseInt(TemplateTaskO.calchaschildren)>0 && !singleSubtaskLongerThanParent)
				TemplateTaskO.warning.isParentLongEnough = (TemplateTaskO.duration >= TemplateTaskO.totalChildDuration);
			else
				TemplateTaskO.warning.isParentLongEnough = true;

			TemplateTaskO.warning.primaryAssigneeEmpty = (TemplateTaskO.primary_assignee == '' || TemplateTaskO.primary_assignee == null);

			// STRY0095897
			TemplateTaskO.warning.taskingAuthorityEmpty = (TemplateTaskO.tasking_authority == '' || TemplateTaskO.tasking_authority == null);
			TemplateTaskO.warning.primaryOfficeEmpty = (TemplateTaskO.primary_office == '' || TemplateTaskO.primary_office == null);
		}
	},
    type: 'TemplateWidgetData'
};
